+//! Hacker News API types.
+
+use serde::{Deserialize, Serialize};
+
+/// A Hacker News item (story, comment, job, poll, or pollopt).
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Item {
+    /// The item's unique ID.
+    pub id: u64,
+
+    /// The type of item: "job", "story", "comment", "poll", or "pollopt".
+    #[serde(rename = "type")]
+    pub item_type: Option<String>,
+
+    /// The username of the item's author.
+    pub by: Option<String>,
+
+    /// Creation date of the item, in Unix Time.
+    pub time: Option<u64>,
+
+    /// The comment, story, or poll text (HTML).
+    pub text: Option<String>,
+
+    /// `true` if the item is dead.
+    #[serde(default)]
+    pub dead: bool,
+
+    /// The comment's parent item ID.
+    pub parent: Option<u64>,
+
+    /// The pollopt's associated poll ID.
+    pub poll: Option<u64>,
+
+    /// The IDs of the item's comments, in display order.
+    #[serde(default)]
+    pub kids: Vec<u64>,
+
+    /// The URL of the story.
+    pub url: Option<String>,
+
+    /// The story's score.
+    pub score: Option<i64>,
+
+    /// The title of the story, poll, or job.
+    pub title: Option<String>,
+
+    /// A list of related pollopts, in display order.
+    #[serde(default)]
+    pub parts: Vec<u64>,
+
+    /// The total comment count for stories and polls.
+    pub descendants: Option<u64>,
+
+    /// `true` if the item is deleted.
+    #[serde(default)]
+    pub deleted: bool,
+}
+
+/// A Hacker News user.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct User {
+    /// The user's unique username (case-sensitive).
+    pub id: String,
+
+    /// Creation date of the user, in Unix Time.
+    pub created: u64,
+
+    /// The user's karma.
+    pub karma: i64,
+
+    /// The user's optional self-description (HTML).
+    pub about: Option<String>,
+
+    /// List of the user's stories, polls, and comments.
+    #[serde(default)]
+    pub submitted: Vec<u64>,
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
