+
+    #[test]
+    fn job_deserialization() {
+        let json = serde_json::json!({
+            "id": 192327,
+            "type": "job",
+            "by": "justin",
+            "time": 1210981217,
+            "title": "Justin.tv is looking for a lead architect",
