+    }
+
+    #[test]
+    fn poll_deserialization() {
+        let json = serde_json::json!({
+            "id": 126809,
+            "type": "poll",
+            "by": "pg",
+            "time": 1204403652,
+            "title": "Poll: What would you work on?",
