+                if !resp.status().is_success() {
+                    let text = resp.text().await.unwrap_or_default();
+                    warn!(status, "Mastodon POST request failed");
+                    let decision = classify_http_status(status, None);
+                    let err = MastodonError::Api {
+                        status,
+                        message: text,
